from pydantic_ai import Agent, ResultValidator
from vex import Vex
from pydantic import BaseModel

class EmailIntent(BaseModel):
    action: str  # 'reply', 'forward', 'archive', 'delegate'
    priority: str  # 'low', 'medium', 'high', 'urgent'
    confidence: float

@vex.guard(  # Vex integration
    verifiers=[
        'pii_filter',
        'tone_check',
        {'name': 'intent_accuracy', 'threshold': 0.8}
    ]
)
def intent_detector_agent():
    agent = Agent(
        model='gpt-4o',
        result_model=EmailIntent,
        result_validator=VexResultValidator()
    )
    return agent

class VexResultValidator(ResultValidator):
    async def __call__(self, output: EmailIntent) -> bool:
        vex_client = Vex(client_id='your-key')
        result = await vex_client.verify({
            'output': output.model_dump(),
            'context': {'domain': 'email_intent'}
        })
        return result.passed

import asyncio
from pydantic_ai import Agent
from vex import Vex

class AttachmentResult(BaseModel):
    filename: str
    size_kb: int
    safe_to_attach: bool
    mime_type: str
    pii_detected: bool

@vex.guard(verifiers=['file_security', 'pii_scan'])
def attachment_handler_agent():
    agent = Agent(
        model='gpt-4o-mini',
        result_model=AttachmentResult,
        tools=[
            {'name': 'scan_file', 'description': 'Scan attachment for malware/PII'}
        ]
    )
    return agent

async def process_attachments(email_attachments: list[bytes]):
    vex = Vex(client_id='your-key')
    results = []

    for attachment in email_attachments:
        result = await attachment_handler_agent().run({
            'attachments': [attachment],
            'vex_context': {'verifiers': ['malware_scan', 'pii_filter']}
        })

        # Vex double-check
        vex_result = await vex.verify({
            'attachment_analysis': result.model_dump(),
            'file_content': attachment[:1024]  # sample
        })

        if vex_result.passed and not result.pii_detected:
            results.append(result)

    return results
